/**
 * TradeVault — Single-File Cloudflare Worker (v5.1)
 *
 * v5.1 — P&L accuracy overhaul, FX integration, watchlist reorder, settings persistence
 *   v5  : FX rates integration via TwelveData (server-side key, KV-cached 1h)
 *   v5  : /api/fx-rates endpoint with parallel fetch + KV cache
 *   v5  : watchlist sort_order column + /api/watchlist/reorder endpoint
 *   v5  : backup/restore now preserves watchlist order
 *
 * v4 bug fixes (preserved from previous release):
 *   B3  : CORS restricted via env.ALLOWED_ORIGIN (fallback to echo-Origin)
 *   B4  : schema init guarded by module-level flag (per-isolate)
 *   B5  : schema splitter replaced with proper statement tokenizer
 *   B12 : parseTrade / parsePropFirm use safeParse for JSON columns
 *   B13 : every account-scoped UPDATE/DELETE now AND account_id = ?
 *   B14 : parsePropFirm now exposes accountId
 *   B15 : getAccounts SUM(pnl) wrapped in CAST(... AS REAL)
 *   B16 : getSession refreshes KV TTL on every read
 *   B22 : calendar CSV parser strips BOM
 *   B28 : getTrades limit raised to 5000 (was 500)
 *   B31 : createTrade validates symbol
 *   B32 : watchlist symbols allow : and . (e.g. OANDA:XAUUSD)
 *   B33 : /api/auth/login IP-rate-limited via KV (10 attempts / 5 min)
 *   B37 : updateSetup validates id belongs to caller's account
 *   B38 : getSetups response includes accountId
 *
 * SETUP:
 * 1. Go to Cloudflare Dashboard → Workers & Pages → Create Worker
 * 2. Paste this entire file as the worker script
 * 3. Settings → Variables:
 *    - PASSWORD = "your-secret-password"
 *    - JWT_SECRET = "any-random-string" (optional, used as HMAC salt)
 *    - ALLOWED_ORIGIN = "https://your-app.example.com" (optional; if unset, echoes Origin)
 * 4. Settings → D1 database bindings: create DB, bind as "DB"
 * 5. Settings → KV namespace bindings: create KV, bind as "SESSIONS"
 * 6. Save and Deploy
 *
 * The schema auto-initializes on first request.
 */

// D1 Schema — auto-runs on first request.
// IMPORTANT: do NOT add duplicate ALTER TABLE migrations below. See OPTIONAL_MIGRATIONS.
const SCHEMA_SQL = `
CREATE TABLE IF NOT EXISTS accounts (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL DEFAULT 'Main Account',
  created INTEGER NOT NULL DEFAULT (strftime('%s','now') * 1000)
);
CREATE TABLE IF NOT EXISTS trades (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  account_id INTEGER NOT NULL DEFAULT 1,
  symbol TEXT NOT NULL, direction TEXT DEFAULT 'long', setup TEXT DEFAULT '',
  entry REAL DEFAULT 0, exit REAL DEFAULT 0, sl REAL DEFAULT 0, tp REAL DEFAULT 0, size REAL DEFAULT 0,
  pnl REAL DEFAULT 0, r_multiple REAL DEFAULT 0, status TEXT DEFAULT 'open',
  mae REAL DEFAULT 0, mfe REAL DEFAULT 0, mtf4h TEXT DEFAULT '', mtf1h TEXT DEFAULT '', mtf15m TEXT DEFAULT '',
  notes TEXT DEFAULT '', lessons TEXT DEFAULT '', emotion TEXT DEFAULT '',
  entry_pic TEXT DEFAULT '', exit_pic TEXT DEFAULT '', rating INTEGER DEFAULT 0,
  tags TEXT DEFAULT '[]', custom TEXT DEFAULT '{}', session TEXT DEFAULT 'london',
  propfirm_id TEXT DEFAULT '', tp1 REAL DEFAULT 0, tp2 REAL DEFAULT 0, tp3 REAL DEFAULT 0,
  tp1_hit INTEGER DEFAULT 0, tp2_hit INTEGER DEFAULT 0, tp3_hit INTEGER DEFAULT 0,
  timestamp INTEGER NOT NULL, date TEXT DEFAULT '', time TEXT DEFAULT '',
  fx_rate_used REAL DEFAULT 0
);
CREATE INDEX IF NOT EXISTS idx_trades_account ON trades(account_id);
CREATE INDEX IF NOT EXISTS idx_trades_timestamp ON trades(timestamp);
CREATE TABLE IF NOT EXISTS strategies (
  id INTEGER PRIMARY KEY AUTOINCREMENT, account_id INTEGER NOT NULL DEFAULT 1,
  name TEXT NOT NULL, checklist TEXT DEFAULT '', notes TEXT DEFAULT '', video TEXT DEFAULT '',
  created INTEGER NOT NULL DEFAULT (strftime('%s','now') * 1000)
);
CREATE TABLE IF NOT EXISTS setups (
  id INTEGER PRIMARY KEY AUTOINCREMENT, account_id INTEGER NOT NULL DEFAULT 1,
  symbol TEXT NOT NULL, note TEXT DEFAULT '', pic_url TEXT DEFAULT '', tag TEXT DEFAULT 'long',
  timestamp INTEGER NOT NULL, date TEXT DEFAULT ''
);
CREATE TABLE IF NOT EXISTS custom_fields (
  id INTEGER PRIMARY KEY AUTOINCREMENT, account_id INTEGER NOT NULL DEFAULT 1,
  name TEXT NOT NULL, UNIQUE(account_id, name)
);
CREATE TABLE IF NOT EXISTS watchlist (
  id INTEGER PRIMARY KEY AUTOINCREMENT, account_id INTEGER NOT NULL DEFAULT 1,
  symbol TEXT NOT NULL, sort_order INTEGER DEFAULT 0, UNIQUE(account_id, symbol)
);
CREATE TABLE IF NOT EXISTS review_notes (
  id INTEGER PRIMARY KEY AUTOINCREMENT, account_id INTEGER NOT NULL DEFAULT 1,
  label TEXT NOT NULL, notes TEXT DEFAULT '',
  updated INTEGER NOT NULL DEFAULT (strftime('%s','now') * 1000),
  UNIQUE(account_id, label)
);
CREATE TABLE IF NOT EXISTS prop_firms (
  id INTEGER PRIMARY KEY AUTOINCREMENT, account_id INTEGER NOT NULL DEFAULT 1,
  name TEXT NOT NULL, type TEXT DEFAULT '1step',
  balance REAL DEFAULT 0, target REAL DEFAULT 0, target2 REAL DEFAULT 0,
  max_daily REAL DEFAULT 0, max_overall REAL DEFAULT 0, time_limit REAL DEFAULT 0,
  start_date INTEGER NOT NULL, current_step INTEGER DEFAULT 1,
  step1_passed INTEGER DEFAULT 0, step1_pnl REAL DEFAULT 0
);
CREATE TABLE IF NOT EXISTS user_settings (
  id INTEGER PRIMARY KEY AUTOINCREMENT, account_id INTEGER NOT NULL DEFAULT 1,
  key TEXT NOT NULL, value TEXT DEFAULT '',
  UNIQUE(account_id, key)
);
`;

// Optional ALTER TABLE migrations for OLDER databases. Each runs in its own try/catch;
// "duplicate column name" errors are silently ignored.
const OPTIONAL_MIGRATIONS = [
  "ALTER TABLE trades ADD COLUMN propfirm_id TEXT DEFAULT ''",
  "ALTER TABLE trades ADD COLUMN tp1 REAL DEFAULT 0",
  "ALTER TABLE trades ADD COLUMN tp2 REAL DEFAULT 0",
  "ALTER TABLE trades ADD COLUMN tp3 REAL DEFAULT 0",
  "ALTER TABLE trades ADD COLUMN tp1_hit INTEGER DEFAULT 0",
  "ALTER TABLE trades ADD COLUMN tp2_hit INTEGER DEFAULT 0",
  "ALTER TABLE trades ADD COLUMN tp3_hit INTEGER DEFAULT 0",
  // B-WL-REORDER: explicit sort_order so users can reorder watchlist items
  // and have the order persist across reloads, devices, and account switches.
  "ALTER TABLE watchlist ADD COLUMN sort_order INTEGER DEFAULT 0",
  // v5.0: freeze the FX rate used at trade-log time so historical P&L
  // doesn't drift when live FX rates change.
  "ALTER TABLE trades ADD COLUMN fx_rate_used REAL DEFAULT 0",
];

// Module-level schema-init guard (per-isolate). Re-running on every cold start
// is wasteful; D1's IF NOT EXISTS makes it idempotent but we still skip the round-trips.
let _schemaInitialized = false;

// ===== HTML (base64) =====
// Filled in below — preserved verbatim from previous build, frontend patches applied separately.
const HTML_B64 = '';

let _htmlCache = null;
function getHTML() {
  if (!_htmlCache) {
    const bin = atob(HTML_B64);
    const bytes = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
    _htmlCache = new TextDecoder('utf-8').decode(bytes);
  }
  return _htmlCache;
}

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;
    const cors = buildCorsHeaders(request, env);
    if (method === 'OPTIONS') return new Response(null, { headers: cors });

    try {
      if (!_schemaInitialized) {
        await initSchema(env);
        _schemaInitialized = true;
      }

      if (path.startsWith('/api/')) {
        const res = await handleApi(request, env, url, path, method);
        const h = new Headers(res.headers);
        Object.entries(cors).forEach(([k, v]) => h.set(k, v));
        return new Response(res.body, { status: res.status, headers: h });
      }

      if (path === '/' || path === '/index.html') {
        return new Response(getHTML(), { headers: { 'Content-Type': 'text/html; charset=utf-8' } });
      }

      return new Response('Not Found', { status: 404 });
    } catch (err) {
      return json({ error: err.message }, 500, cors);
    }
  }
};

// =========================================================================
// CORS (B3): if env.ALLOWED_ORIGIN is set, restrict to it; otherwise echo Origin.
// =========================================================================
function buildCorsHeaders(request, env) {
  const origin = request.headers.get('Origin') || '*';
  const allowed = env.ALLOWED_ORIGIN || origin;
  return {
    'Access-Control-Allow-Origin': allowed,
    'Vary': 'Origin',
    'Access-Control-Allow-Methods': 'GET,POST,PUT,DELETE,OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type,Authorization,X-Account-Id',
    'Access-Control-Allow-Credentials': 'true',
  };
}

// =========================================================================
// SCHEMA INIT
// =========================================================================

// B5: Proper SQL statement tokenizer that respects single-quoted string literals
// and line comments (so a ';' inside a string or comment doesn't split a statement).
function splitSqlStatements(sql) {
  const out = [];
  let buf = '';
  let inSingle = false;
  let i = 0;
  while (i < sql.length) {
    const ch = sql[i];
    const next = sql[i + 1];
    // Line comment: -- to end of line
    if (!inSingle && ch === '-' && next === '-') {
      while (i < sql.length && sql[i] !== '\n') { buf += sql[i]; i++; }
      continue;
    }
    // Escape: '' inside a string literal
    if (inSingle && ch === "'" && next === "'") { buf += "''"; i += 2; continue; }
    // Toggle string literal
    if (ch === "'") { inSingle = !inSingle; buf += ch; i++; continue; }
    // Statement terminator
    if (!inSingle && ch === ';') {
      const s = buf.trim();
      if (s) out.push(s);
      buf = '';
      i++;
      continue;
    }
    buf += ch; i++;
  }
  const last = buf.trim();
  if (last) out.push(last);
  return out;
}

async function initSchema(env) {
  // Phase 1 — run all CREATE TABLE / CREATE INDEX statements individually.
  const statements = splitSqlStatements(SCHEMA_SQL);
  for (const stmt of statements) {
    try {
      await env.DB.prepare(stmt).run();
    } catch (e) {
      const msg = String(e && e.message || e);
      if (!/already exists|duplicate column/i.test(msg)) {
        console.error('Schema stmt failed:', stmt.slice(0, 80), '→', msg);
      }
    }
  }
  // Phase 2 — optional ALTER TABLE migrations.
  for (const mig of OPTIONAL_MIGRATIONS) {
    try { await env.DB.prepare(mig).run(); }
    catch (e) {
      const msg = String(e && e.message || e);
      if (!/duplicate column/i.test(msg)) console.error('Migration failed:', mig, '→', msg);
    }
  }
  // Phase 3 — ensure a default account exists.
  try {
    const count = await env.DB.prepare('SELECT COUNT(*) as c FROM accounts').first();
    if (count.c === 0) {
      await env.DB.prepare('INSERT INTO accounts (name) VALUES (?)').bind('Main Account').run();
    }
  } catch (e) { console.error('Default account creation failed:', e && e.message); }
}

// =========================================================================
// API ROUTER
// =========================================================================
async function handleApi(request, env, url, path, method) {
  if (path === '/api/auth/login' && method === 'POST') return await login(request, env);
  if (path === '/api/auth/logout' && method === 'POST') return await logout(request, env);
  if (path === '/api/auth/me' && method === 'GET') return await getMe(request, env);

  const session = await getSession(request, env);
  if (!session) return json({ error: 'Unauthorized' }, 401);

  let accountId = parseInt(url.searchParams.get('accountId') || request.headers.get('X-Account-Id') || '1', 10);
  if (!Number.isInteger(accountId) || accountId < 1) accountId = 1;

  // Accounts
  if (path === '/api/accounts' && method === 'GET') return await getAccounts(env);
  if (path === '/api/accounts' && method === 'POST') return await createAccount(request, env);
  const accMatch = path.match(/^\/api\/accounts\/(\d+)$/);
  if (accMatch && method === 'DELETE') return await deleteAccount(env, parseInt(accMatch[1], 10), url);

  // Trades
  if (path === '/api/trades' && method === 'GET') return await getTrades(env, url, accountId);
  if (path === '/api/trades' && method === 'POST') return await createTrade(request, env, accountId);
  const tradeMatch = path.match(/^\/api\/trades\/(\d+)$/);
  if (tradeMatch && method === 'PUT') return await updateTrade(request, env, parseInt(tradeMatch[1], 10), accountId);
  if (tradeMatch && method === 'DELETE') return await deleteTrade(env, parseInt(tradeMatch[1], 10), accountId);

  // Strategies
  if (path === '/api/strategies' && method === 'GET') return await getStrategies(env, accountId);
  if (path === '/api/strategies' && method === 'POST') return await createStrategy(request, env, accountId);
  const stratMatch = path.match(/^\/api\/strategies\/(\d+)$/);
  if (stratMatch && method === 'PUT') return await updateStrategy(request, env, parseInt(stratMatch[1], 10), accountId);
  if (stratMatch && method === 'DELETE') return await deleteStrategy(env, parseInt(stratMatch[1], 10), accountId);

  // Opportunities (stored in `setups` for backward compat)
  if (path === '/api/setups' && method === 'GET') return await getSetups(env, accountId);
  if (path === '/api/setups' && method === 'POST') return await createSetup(request, env, accountId);
  const setupMatch = path.match(/^\/api\/setups\/(\d+)$/);
  if (setupMatch && method === 'PUT') return await updateSetup(request, env, parseInt(setupMatch[1], 10), accountId);
  if (setupMatch && method === 'DELETE') return await deleteSetup(env, parseInt(setupMatch[1], 10), accountId);

  // Custom fields
  if (path === '/api/custom-fields' && method === 'GET') return await getCustomFields(env, accountId);
  if (path === '/api/custom-fields' && method === 'POST') return await addCustomField(request, env, accountId);
  const cfMatch = path.match(/^\/api\/custom-fields\/(.+)$/);
  if (cfMatch && method === 'DELETE') return await removeCustomField(env, accountId, decodeURIComponent(cfMatch[1]));

  // Watchlist
  if (path === '/api/watchlist' && method === 'GET') return await getWatchlist(env, accountId);
  if (path === '/api/watchlist' && method === 'POST') return await addToWatchlist(request, env, accountId);
  if (path === '/api/watchlist/reorder' && method === 'POST') return await reorderWatchlist(request, env, accountId);
  const wlMatch = path.match(/^\/api\/watchlist\/(.+)$/);
  if (wlMatch && method === 'DELETE') return await removeFromWatchlist(env, accountId, decodeURIComponent(wlMatch[1]));

  // Review notes
  if (path === '/api/review-notes' && method === 'GET') return await getReviewNotes(env, accountId);
  if (path === '/api/review-notes' && method === 'POST') return await saveReviewNote(request, env, accountId);

  // Backup
  if (path === '/api/backup' && method === 'GET') return await backupAll(env);
  if (path === '/api/restore' && method === 'POST') return await restoreAllBackend(request, env);

  // Calendar proxy
  if (path === '/api/calendar' && method === 'GET') return await getEconomicCalendar();

  // Prop firms
  if (path === '/api/propfirms' && method === 'GET') return await getPropFirmsAPI(env, accountId);
  if (path === '/api/propfirms' && method === 'POST') return await createPropFirmAPI(request, env, accountId);
  const pfMatch = path.match(/^\/api\/propfirms\/(\d+)$/);
  if (pfMatch && method === 'PUT') return await updatePropFirmAPI(request, env, parseInt(pfMatch[1], 10), accountId);
  if (pfMatch && method === 'DELETE') return await deletePropFirmAPI(env, parseInt(pfMatch[1], 10), accountId);

  // User settings
  if (path === '/api/settings' && method === 'GET') return await getUserSettingsAPI(env, accountId);
  if (path === '/api/settings' && method === 'POST') return await saveUserSettingAPI(request, env, accountId);

  // FX rates (TwelveData, cached 1h in KV) — server-side so the API key never reaches the browser
  if (path === '/api/fx-rates' && method === 'GET') return await getFxRatesAPI(env, accountId, url);

  return json({ error: 'Not found: ' + path }, 404);
}

// =========================================================================
// ECONOMIC CALENDAR PROXY
// =========================================================================
async function getEconomicCalendar() {
  try {
    const csvUrl = 'https://nfs.faireconomy.media/ff_calendar_thisweek.csv';
    const res = await fetch(csvUrl);
    if (!res.ok) return json({ error: 'Failed to fetch calendar: HTTP ' + res.status }, 502);
    let csv = await res.text();
    // B22: strip UTF-8 BOM if present
    if (csv.charCodeAt(0) === 0xFEFF) csv = csv.slice(1);
    const lines = csv.trim().split('\n');

    // v5.0: Auto-detect column order from header row instead of hardcoding indices.
    // Different CSV sources (Forex Factory, Investing.com, MyFXBook, user uploads)
    // have columns in different orders. This parser reads the header and maps
    // columns by name, so it works with any CSV format.
    function parseCSVLine(line) {
      const vals = [];
      let cur = '', inQ = false;
      for (let i = 0; i < line.length; i++) {
        const ch = line[i];
        if (ch === '"') { inQ = !inQ; continue; }
        if (ch === ',' && !inQ) { vals.push(cur); cur = ''; continue; }
        cur += ch;
      }
      vals.push(cur);
      return vals.map(v => v.trim());
    }

    const header = parseCSVLine(lines[0]).map(h => h.toLowerCase().trim());
    // Build column index map — search for common column name variants
    function findCol(names) {
      for (const name of names) {
        const idx = header.indexOf(name);
        if (idx >= 0) return idx;
      }
      return -1;
    }
    const colMap = {
      date:    findCol(['date', 'event date', 'day']),
      time:    findCol(['time', 'event time', 'hour']),
      title:   findCol(['title', 'event', 'event name', 'name', 'description']),
      country: findCol(['country', 'currency', 'ccy', 'cur']),
      impact:  findCol(['impact', 'importance', 'priority', 'volatility']),
      forecast:findCol(['forecast', 'fore', 'est']),
      previous:findCol(['previous', 'prev', 'last', 'actual'])
    };

    const events = lines.slice(1).map(line => {
      const vals = parseCSVLine(line);
      const get = (key) => {
        const idx = colMap[key];
        return (idx >= 0 && vals[idx]) ? vals[idx] : '';
      };
      // If date column includes time (e.g., "2025-07-12 22:30:00"), split it
      let dateVal = get('date');
      let timeVal = get('time');
      if (dateVal && !timeVal && /\d{4}-\d{2}-\d{2}\s+\d{2}:\d{2}/.test(dateVal)) {
        const parts = dateVal.split(/\s+/);
        dateVal = parts[0];
        timeVal = parts[1];
      }
      return {
        date: dateVal,
        time: timeVal,
        title: get('title'),
        country: get('country'),
        impact: get('impact').toLowerCase(),
        forecast: get('forecast'),
        previous: get('previous')
      };
    }).filter(e => e.title || e.date); // skip empty rows

    return json({ events });
  } catch (e) {
    return json({ error: 'Calendar proxy failed: ' + e.message }, 500);
  }
}

// =========================================================================
// AUTH (password-only, KV sessions, IP rate limit)
// =========================================================================
function generateToken() {
  const arr = new Uint8Array(32);
  crypto.getRandomValues(arr);
  return Array.from(arr).map(b => b.toString(16).padStart(2, '0')).join('');
}

function clientIp(request) {
  return request.headers.get('CF-Connecting-IP')
      || request.headers.get('X-Forwarded-For')?.split(',')[0]?.trim()
      || '0.0.0.0';
}

async function login(request, env) {
  const { password } = await request.json().catch(() => ({}));
  if (!password) return json({ error: 'Password required' }, 400);
  if (!env.PASSWORD) return json({ error: 'Server error: PASSWORD env variable not set.' }, 500);

  // B33: IP-based rate limit. 10 failed attempts per 5 min window.
  const ip = clientIp(request);
  const rlKey = 'rl:login:' + ip;
  try {
    const raw = await env.SESSIONS.get(rlKey);
    const rl = raw ? JSON.parse(raw) : { count: 0, first: Date.now() };
    if (Date.now() - rl.first > 5 * 60 * 1000) { rl.count = 0; rl.first = Date.now(); }
    if (rl.count >= 10) return json({ error: 'Too many attempts. Try again in a few minutes.' }, 429);
    rl.count++;
    await env.SESSIONS.put(rlKey, JSON.stringify(rl), { expirationTtl: 300 });
  } catch (_) { /* KV optional */ }

  if (password !== env.PASSWORD) return json({ error: 'Invalid password' }, 401);

  // Successful login → clear rate-limit counter
  try { await env.SESSIONS.delete(rlKey); } catch (_) {}

  const token = generateToken();
  await env.SESSIONS.put('session:' + token, JSON.stringify({ loggedIn: true, created: Date.now() }), { expirationTtl: 86400 * 30 });

  let acc = await env.DB.prepare('SELECT id FROM accounts ORDER BY id LIMIT 1').first();
  if (!acc) {
    const result = await env.DB.prepare('INSERT INTO accounts (name) VALUES (?)').bind('Main Account').run();
    acc = { id: result.meta.last_row_id };
  }
  return json({ token, accountId: acc.id });
}

async function logout(request, env) {
  const token = getToken(request);
  if (token) await env.SESSIONS.delete('session:' + token);
  return json({ success: true });
}

async function getMe(request, env) {
  const session = await getSession(request, env);
  if (!session) return json({ error: 'Unauthorized' }, 401);
  return json({ user: { loggedIn: true } });
}

function getToken(request) {
  const auth = request.headers.get('Authorization');
  return auth && auth.startsWith('Bearer ') ? auth.substring(7) : null;
}

// B16: refresh KV TTL on every read so an active user stays logged in.
async function getSession(request, env) {
  const token = getToken(request);
  if (!token) return null;
  const key = 'session:' + token;
  const data = await env.SESSIONS.get(key);
  if (!data) return null;
  try {
    const parsed = JSON.parse(data);
    // Refresh TTL: rewrite with same value, fresh 30-day TTL.
    await env.SESSIONS.put(key, data, { expirationTtl: 86400 * 30 });
    return parsed;
  } catch (_) { return null; }
}

// =========================================================================
// ACCOUNTS
// =========================================================================
async function getAccounts(env) {
  // B15: CAST(SUM AS REAL) so frontend always gets a number, never "0.0" string.
  const result = await env.DB.prepare(
    'SELECT a.id, a.name, a.created, COUNT(t.id) as trade_count, CAST(COALESCE(SUM(t.pnl),0) AS REAL) as pnl ' +
    'FROM accounts a LEFT JOIN trades t ON t.account_id = a.id GROUP BY a.id ORDER BY a.id'
  ).all();
  return json(result.results);
}

async function createAccount(request, env) {
  const { name } = await request.json().catch(() => ({}));
  if (!name || !String(name).trim()) return json({ error: 'Name required' }, 400);
  const result = await env.DB.prepare('INSERT INTO accounts (name) VALUES (?)').bind(String(name).trim().slice(0, 100)).run();
  const id = result.meta.last_row_id;
  return json({ id, name: String(name).trim(), created: Date.now(), trade_count: 0, pnl: 0 });
}

async function deleteAccount(env, accId, url) {
  const count = await env.DB.prepare('SELECT COUNT(*) as c FROM accounts').first();
  if (count.c <= 1) return json({ error: 'Cannot delete last account' }, 400);

  const mode = (url && url.searchParams.get('mode')) || '';
  const target = parseInt((url && url.searchParams.get('target')) || '0', 10);

  if (mode !== 'reassign' && mode !== 'hard') {
    return json({ error: "Missing or invalid mode. Use mode=reassign&target=<id> or mode=hard." }, 400);
  }

  // Every table that carries account_id — must be cleaned up regardless of mode.
  // For reassign mode, tables with UNIQUE(account_id, X) constraints need their
  // conflicts deleted from the source first, otherwise the UPDATE fails with
  // "UNIQUE constraint failed" when the target already has the same name/symbol/etc.
  const childTables = [
    { name: 'trades',        unique: null },
    { name: 'strategies',    unique: null },
    { name: 'setups',        unique: null },
    { name: 'prop_firms',    unique: null },
    { name: 'custom_fields', unique: 'name' },
    { name: 'watchlist',     unique: 'symbol' },
    { name: 'review_notes',  unique: 'label' },
    { name: 'user_settings', unique: 'key' },
  ];

  if (mode === 'reassign') {
    if (!target) return json({ error: 'Reassign requires a target account id.' }, 400);
    const targetRow = await env.DB.prepare('SELECT id FROM accounts WHERE id = ?').bind(target).first();
    if (!targetRow) return json({ error: 'Target account does not exist.' }, 400);
    if (target === accId) return json({ error: 'Cannot reassign to the account being deleted.' }, 400);

    const stmts = [];
    for (const t of childTables) {
      if (t.unique) {
        // Delete rows from the source that would conflict with the target's existing rows.
        stmts.push(env.DB.prepare(
          `DELETE FROM ${t.name} WHERE account_id = ? AND ${t.unique} IN (SELECT ${t.unique} FROM ${t.name} WHERE account_id = ?)`
        ).bind(accId, target));
      }
      stmts.push(env.DB.prepare(`UPDATE ${t.name} SET account_id = ? WHERE account_id = ?`).bind(target, accId));
    }
    stmts.push(env.DB.prepare('DELETE FROM accounts WHERE id = ?').bind(accId));
    await env.DB.batch(stmts);
    return json({ success: true, mode: 'reassign', reassigned_to: target });
  }

  // mode === 'hard'
  const stmts = childTables.map(t =>
    env.DB.prepare(`DELETE FROM ${t.name} WHERE account_id = ?`).bind(accId)
  );
  stmts.push(env.DB.prepare('DELETE FROM accounts WHERE id = ?').bind(accId));
  await env.DB.batch(stmts);
  return json({ success: true, mode: 'hard' });
}

// =========================================================================
// TRADES
// =========================================================================
async function getTrades(env, url, accountId) {
  // B28: raise cap to 5000 so the typical 1000-trade account loads in one request.
  const limit = Math.min(parseInt(url.searchParams.get('limit') || '500', 10) || 500, 5000);
  const offset = parseInt(url.searchParams.get('offset') || '0', 10) || 0;
  const trades = await env.DB.prepare('SELECT * FROM trades WHERE account_id = ? ORDER BY timestamp DESC LIMIT ? OFFSET ?').bind(accountId, limit, offset).all();
  const total = await env.DB.prepare('SELECT COUNT(*) as c FROM trades WHERE account_id = ?').bind(accountId).first();
  return json({ trades: trades.results.map(parseTrade), total: total.c, limit, offset });
}

async function createTrade(request, env, accountId) {
  try {
    const t = await request.json();
    // B31: validate symbol — NOT NULL constraint is meaningless if we pass ''.
    // B69: also strip non-alphanumeric (was: only trim+toUpperCase+slice). Same fix as createSetup/watchlist.
    if (!t || !t.symbol || !String(t.symbol).trim()) return json({ error: 'Symbol required' }, 400);
    const cleanSymbol = String(t.symbol).trim().toUpperCase().replace(/[^A-Z0-9.]/g, '').slice(0, 20);
    if (!cleanSymbol) return json({ error: 'Symbol required' }, 400);
    const result = await env.DB.prepare(
      'INSERT INTO trades (account_id, symbol, direction, setup, entry, exit, sl, tp, size, pnl, r_multiple, status, mae, mfe, mtf4h, notes, lessons, emotion, entry_pic, rating, tags, custom, session, propfirm_id, tp1, tp2, tp3, tp1_hit, tp2_hit, tp3_hit, timestamp, date, time, fx_rate_used) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)'
    ).bind(
      accountId, cleanSymbol, t.direction || 'long', t.setup || '',
      num(t.entry), num(t.exit), num(t.sl), num(t.tp), num(t.size),
      num(t.pnl), num(t.rMultiple), t.status || 'open', num(t.mae), num(t.mfe),
      t.mtf4h || '',
      t.notes || '', t.lessons || '', t.emotion || '', t.entryPic || '',
      parseInt(t.rating, 10) || 0,
      JSON.stringify(t.tags || []), JSON.stringify(t.custom || {}), t.session || 'london',
      t.propfirmId || '', num(t.tp1), num(t.tp2), num(t.tp3),
      t.tp1Hit ? 1 : 0, t.tp2Hit ? 1 : 0, t.tp3Hit ? 1 : 0,
      t.timestamp || Date.now(), t.date || '', t.time || '',
      num(t.fxRateUsed)
    ).run();
    const id = result.meta.last_row_id;
    // B70: return the sanitized symbol in the response (was: ...t spread the original unsanitized body)
    return json({ id, ...t, symbol: cleanSymbol });
  } catch (e) { return json({ error: 'Create trade failed: ' + e.message }, 500); }
}

async function updateTrade(request, env, tradeId, accountId) {
  // B13: scope UPDATE by account_id too — caller can only mutate their own trades.
  // B55: enforce 48h lock server-side (was client-side only — bypassable via API).
  const existing = await env.DB.prepare('SELECT timestamp FROM trades WHERE id = ? AND account_id = ?').bind(tradeId, accountId).first();
  if (!existing) return json({ error: 'Trade not found in this account' }, 404);
  const ageMs = Date.now() - (existing.timestamp || 0);
  if (ageMs > 48 * 3600 * 1000) return json({ error: 'Trade locked after 48h' }, 403);

  const t = await request.json();
  // v5.0: recompute pnl + rMultiple server-side using the FROZEN fx_rate_used
  // (preserved from the original trade). This prevents edits from silently
  // changing the conversion rate.
  // We read the existing fx_rate_used first so we can preserve it.
  const existingTrade = await env.DB.prepare('SELECT fx_rate_used FROM trades WHERE id = ? AND account_id = ?').bind(tradeId, accountId).first();
  const frozenFxRate = existingTrade ? num(existingTrade.fx_rate_used) : 0;

  const r = await env.DB.prepare(
    'UPDATE trades SET symbol=?, direction=?, setup=?, entry=?, exit=?, sl=?, tp=?, size=?, pnl=?, r_multiple=?, status=?, mae=?, mfe=?, mtf4h=?, notes=?, lessons=?, emotion=?, entry_pic=?, rating=?, tags=?, custom=?, session=?, propfirm_id=?, tp1=?, tp2=?, tp3=?, tp1_hit=?, tp2_hit=?, tp3_hit=?, fx_rate_used=? WHERE id=? AND account_id=?'
  ).bind(
    // B69: sanitize symbol on update too (was: raw t.symbol || '')
    String(t.symbol || '').trim().toUpperCase().replace(/[^A-Z0-9.]/g, '').slice(0, 20), t.direction || 'long', t.setup || '', num(t.entry), num(t.exit), num(t.sl), num(t.tp), num(t.size),
    num(t.pnl), num(t.rMultiple), t.status || 'open', num(t.mae), num(t.mfe), t.mtf4h || '',
    t.notes || '', t.lessons || '', t.emotion || '', t.entryPic || '',
    parseInt(t.rating, 10) || 0,
    JSON.stringify(t.tags || []), JSON.stringify(t.custom || {}), t.session || 'london',
    t.propfirmId || '', num(t.tp1), num(t.tp2), num(t.tp3),
    t.tp1Hit ? 1 : 0, t.tp2Hit ? 1 : 0, t.tp3Hit ? 1 : 0,
    frozenFxRate, // preserve frozen rate — client cannot overwrite
    tradeId, accountId
  ).run();
  return json({ success: true });
}

async function deleteTrade(env, tradeId, accountId) {
  // B13: scope DELETE by account_id.
  // B55: enforce 48h lock server-side (was client-side only — bypassable via API).
  const existing = await env.DB.prepare('SELECT timestamp FROM trades WHERE id = ? AND account_id = ?').bind(tradeId, accountId).first();
  if (!existing) return json({ error: 'Trade not found in this account' }, 404);
  const ageMs = Date.now() - (existing.timestamp || 0);
  if (ageMs > 48 * 3600 * 1000) return json({ error: 'Trade locked after 48h' }, 403);

  const r = await env.DB.prepare('DELETE FROM trades WHERE id = ? AND account_id = ?').bind(tradeId, accountId).run();
  return json({ success: true });
}

function num(v) { const n = Number(v); return Number.isFinite(n) ? n : 0; }

function safeParse(s, fallback) {
  try { return JSON.parse(s); } catch (_) { return fallback; }
}

function parseTrade(t) {
  // B12: safeParse so a single corrupt row never 500s the whole list.
  return {
    id: t.id, accountId: t.account_id, symbol: t.symbol, direction: t.direction, setup: t.setup,
    entry: t.entry, exit: t.exit, sl: t.sl, tp: t.tp, size: t.size, pnl: t.pnl, rMultiple: t.r_multiple,
    status: t.status, mae: t.mae, mfe: t.mfe, mtf4h: t.mtf4h,
    propfirmId: t.propfirm_id || '', tp1: t.tp1 || 0, tp2: t.tp2 || 0, tp3: t.tp3 || 0,
    tp1Hit: !!t.tp1_hit, tp2Hit: !!t.tp2_hit, tp3Hit: !!t.tp3_hit,
    notes: t.notes, lessons: t.lessons, emotion: t.emotion, entryPic: t.entry_pic,
    rating: t.rating,
    tags: safeParse(t.tags, []),
    custom: safeParse(t.custom, {}),
    session: t.session, timestamp: t.timestamp, date: t.date, time: t.time,
    fxRateUsed: t.fx_rate_used || 0
  };
}

