// =========================================================================
// FX RATES (TwelveData) — server-side fetch + KV cache (1h TTL).
// The API key is read from user_settings (key = "twelvedata_apikey") so it
// never travels to the browser. Cached in KV under "fx_rates:{accountId}".
//
// ?symbols=USD/JPY,USD/CAD,... — optional comma-separated list. Defaults to
// the 7 majors needed for quote->USD conversion.
// ?force=1 — bypass KV cache and force a fresh fetch.
// =========================================================================
const DEFAULT_FX_SYMBOLS = ['USD/JPY', 'USD/CAD', 'USD/CHF', 'EUR/USD', 'GBP/USD', 'AUD/USD', 'NZD/USD'];

async function getFxRatesAPI(env, accountId, url) {
  const symbolsParam = url.searchParams.get('symbols');
  const symbols = symbolsParam
    ? symbolsParam.split(',').map(s => s.trim().toUpperCase()).filter(Boolean)
    : DEFAULT_FX_SYMBOLS;
  const force = url.searchParams.get('force') === '1';

  // 1. Try KV cache first (unless ?force=1)
  const cacheKey = 'fx_rates:' + accountId;
  if (!force && env.SESSIONS) {
    try {
      const cached = await env.SESSIONS.get(cacheKey, 'json');
      if (cached && cached.fetchedAt && (Date.now() - cached.fetchedAt < 60 * 60 * 1000)) {
        // Refresh TTL on read so active users keep their cache warm
        await env.SESSIONS.put(cacheKey, JSON.stringify(cached), { expirationTtl: 3600 }).catch(() => {});
        return json({ rates: cached.rates, fetchedAt: cached.fetchedAt, source: cached.source || 'twelvedata', cached: true });
      }
    } catch (_) { /* cache miss / corrupt — fall through to fetch */ }
  }

  // 2. Read the API key from user_settings (D1)
  const row = await env.DB.prepare('SELECT value FROM user_settings WHERE account_id = ? AND key = ?').bind(accountId, 'twelvedata_apikey').first();
  const apiKey = row && row.value ? String(row.value).trim() : '';
  if (!apiKey) {
    return json({ error: 'TwelveData API key not set. Open Settings → FX Rates & Currency to add one.', rates: {}, fetchedAt: 0, source: 'none' }, 200);
  }

  // 3. Fetch each symbol in parallel from TwelveData
  //    Endpoint: https://api.twelvedata.com/price?symbol=USD/JPY&apikey=KEY
  //    Response: { "price": "150.23", "currency": "USD", ... }  OR  { "status": "error", "message": "..." }
  const results = await Promise.all(symbols.map(async sym => {
    try {
      const r = await fetch('https://api.twelvedata.com/price?symbol=' + encodeURIComponent(sym) + '&apikey=' + encodeURIComponent(apiKey), {
        headers: { 'Accept': 'application/json' }
      });
      if (!r.ok) return { symbol: sym, error: 'HTTP ' + r.status };
      const j = await r.json();
      if (j && j.status === 'error') return { symbol: sym, error: j.message || 'API error' };
      const price = parseFloat(j && j.price);
      if (!Number.isFinite(price)) return { symbol: sym, error: 'No price in response' };
      return { symbol: sym, price };
    } catch (e) {
      return { symbol: sym, error: e.message };
    }
  }));

  const rates = {};
  const errors = {};
  results.forEach(r => {
    if (r.price !== undefined) rates[r.symbol] = r.price;
    else errors[r.symbol] = r.error;
  });

  const payload = { rates, errors, fetchedAt: Date.now(), source: 'twelvedata', cached: false };

  // 4. Cache in KV for 1h (only if at least one rate came back)
  if (env.SESSIONS && Object.keys(rates).length > 0) {
    await env.SESSIONS.put(cacheKey, JSON.stringify(payload), { expirationTtl: 3600 }).catch(() => {});
  }

  return json(payload);
}

// =========================================================================
// BACKUP
// =========================================================================
async function backupAll(env) {
  const accounts = await env.DB.prepare('SELECT id, name, created FROM accounts ORDER BY id').all();
  const data = { accounts: accounts.results, trades: {}, strategies: {}, setups: {}, custom_fields: {}, watchlist: {}, review_notes: {}, prop_firms: {}, user_settings: {} };
  for (const acc of accounts.results) {
    data.trades[acc.id] = (await env.DB.prepare('SELECT * FROM trades WHERE account_id = ?').bind(acc.id).all()).results.map(parseTrade);
    data.strategies[acc.id] = (await env.DB.prepare('SELECT * FROM strategies WHERE account_id = ?').bind(acc.id).all()).results;
    data.setups[acc.id] = (await env.DB.prepare('SELECT * FROM setups WHERE account_id = ?').bind(acc.id).all()).results;
    data.custom_fields[acc.id] = (await env.DB.prepare('SELECT name FROM custom_fields WHERE account_id = ?').bind(acc.id).all()).results.map(r => r.name);
    data.watchlist[acc.id] = (await env.DB.prepare('SELECT symbol FROM watchlist WHERE account_id = ? ORDER BY sort_order, id').bind(acc.id).all()).results.map(r => r.symbol);
    data.review_notes[acc.id] = (await env.DB.prepare('SELECT label, notes FROM review_notes WHERE account_id = ?').bind(acc.id).all()).results;
    data.prop_firms[acc.id] = (await env.DB.prepare('SELECT * FROM prop_firms WHERE account_id = ?').bind(acc.id).all()).results.map(parsePropFirm);
    data.user_settings[acc.id] = {};
    (await env.DB.prepare('SELECT key, value FROM user_settings WHERE account_id = ?').bind(acc.id).all()).results.forEach(r => { data.user_settings[acc.id][r.key] = r.value; });
  }
  return json({ version: 3, type: 'trading-dashboard-cloud-backup', created: new Date().toISOString(), data });
}

// B60: POST /api/restore — accepts a cloud-format backup, wipes all existing
// data, and inserts the backup data. This is the inverse of backupAll().
async function restoreAllBackend(request, env) {
  try {
    const backup = await request.json();
    if (!backup || !backup.data || !Array.isArray(backup.data.accounts)) {
      return json({ error: 'Invalid backup format — expected data.accounts array' }, 400);
    }
    const d = backup.data;

    // Wipe all child tables + accounts (in dependency order)
    const wipeStmts = [
      'DELETE FROM trades',
      'DELETE FROM strategies',
      'DELETE FROM setups',
      'DELETE FROM custom_fields',
      'DELETE FROM watchlist',
      'DELETE FROM review_notes',
      'DELETE FROM prop_firms',
      'DELETE FROM user_settings',
      'DELETE FROM accounts',
    ];
    await env.DB.batch(wipeStmts.map(s => env.DB.prepare(s)));

    let accountsRestored = 0, tradesRestored = 0;

    // Restore accounts first (need their IDs for child rows)
    for (const acc of d.accounts) {
      await env.DB.prepare('INSERT INTO accounts (id, name, created) VALUES (?, ?, ?)')
        .bind(acc.id, acc.name || 'Account', acc.created || Date.now()).run();
      accountsRestored++;

      // Restore trades for this account — B75: preserve original trade IDs
      const trades = (d.trades && d.trades[acc.id]) || [];
      for (const t of trades) {
        await env.DB.prepare(
          'INSERT INTO trades (id, account_id, symbol, direction, setup, entry, exit, sl, tp, size, pnl, r_multiple, status, mae, mfe, mtf4h, notes, lessons, emotion, entry_pic, rating, tags, custom, session, propfirm_id, tp1, tp2, tp3, tp1_hit, tp2_hit, tp3_hit, timestamp, date, time, fx_rate_used) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)'
        ).bind(
          t.id || null, acc.id, t.symbol || '', t.direction || 'long', t.setup || '',
          num(t.entry), num(t.exit), num(t.sl), num(t.tp), num(t.size),
          num(t.pnl), num(t.rMultiple), t.status || 'open', num(t.mae), num(t.mfe),
          t.mtf4h || '',
          t.notes || '', t.lessons || '', t.emotion || '', t.entryPic || '',
          parseInt(t.rating, 10) || 0,
          JSON.stringify(t.tags || []), JSON.stringify(t.custom || {}), t.session || 'london',
          t.propfirmId || '', num(t.tp1), num(t.tp2), num(t.tp3),
          t.tp1Hit ? 1 : 0, t.tp2Hit ? 1 : 0, t.tp3Hit ? 1 : 0,
          t.timestamp || Date.now(), t.date || '', t.time || '',
          num(t.fxRateUsed)
        ).run();
        tradesRestored++;
      }

      // Restore strategies — B75: preserve original strategy IDs
      const strategies = (d.strategies && d.strategies[acc.id]) || [];
      for (const s of strategies) {
        await env.DB.prepare('INSERT INTO strategies (id, account_id, name, checklist, notes, video, created) VALUES (?, ?, ?, ?, ?, ?, ?)')
          .bind(s.id || null, acc.id, s.name || '', s.checklist || '', s.notes || '', s.video || '', s.created || Date.now()).run();
      }

      // Restore setups — B75: preserve original setup IDs
      const setups = (d.setups && d.setups[acc.id]) || [];
      for (const su of setups) {
        await env.DB.prepare('INSERT INTO setups (id, account_id, symbol, note, pic_url, tag, timestamp, date) VALUES (?, ?, ?, ?, ?, ?, ?, ?)')
          .bind(su.id || null, acc.id, su.symbol || '', su.note || '', su.picUrl || su.pic_url || '', su.tag || 'long', su.timestamp || Date.now(), su.date || '').run();
      }

      // Restore custom fields
      const cf = (d.custom_fields && d.custom_fields[acc.id]) || [];
      for (const name of cf) {
        await env.DB.prepare('INSERT OR IGNORE INTO custom_fields (account_id, name) VALUES (?, ?)')
          .bind(acc.id, String(name).slice(0, 50)).run();
      }

      // Restore watchlist — preserve order via sort_order
      const wl = (d.watchlist && d.watchlist[acc.id]) || [];
      let wlOrder = 0;
      for (const sym of wl) {
        await env.DB.prepare('INSERT OR IGNORE INTO watchlist (account_id, symbol, sort_order) VALUES (?, ?, ?)')
          .bind(acc.id, String(sym).toUpperCase(), wlOrder++).run();
      }

      // Restore review notes (object: {label: notes})
      const rn = (d.review_notes && d.review_notes[acc.id]) || {};
      if (Array.isArray(rn)) {
        // Some backups store review_notes as array of {label, notes}
        for (const r of rn) {
          await env.DB.prepare('INSERT INTO review_notes (account_id, label, notes, updated) VALUES (?, ?, ?, ?) ON CONFLICT(account_id, label) DO UPDATE SET notes = ?, updated = ?')
            .bind(acc.id, r.label || '', r.notes || '', Date.now(), r.notes || '', Date.now()).run();
        }
      } else {
        for (const [label, notes] of Object.entries(rn)) {
          await env.DB.prepare('INSERT INTO review_notes (account_id, label, notes, updated) VALUES (?, ?, ?, ?) ON CONFLICT(account_id, label) DO UPDATE SET notes = ?, updated = ?')
            .bind(acc.id, label, notes || '', Date.now(), notes || '', Date.now()).run();
        }
      }

      // Restore prop firms — B75: preserve original prop firm IDs (critical: trades reference them by ID)
      const pfs = (d.prop_firms && d.prop_firms[acc.id]) || [];
      for (const pf of pfs) {
        await env.DB.prepare(
          'INSERT INTO prop_firms (id, account_id, name, type, balance, target, target2, max_daily, max_overall, time_limit, start_date, current_step, step1_passed, step1_pnl) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?)'
        ).bind(
          pf.id || null, acc.id, pf.name || '', pf.type || '1step',
          num(pf.balance), num(pf.target), num(pf.target2),
          num(pf.maxDaily), num(pf.maxOverall), num(pf.timeLimit),
          pf.startDate || Date.now(), pf.currentStep || 1, pf.step1Passed ? 1 : 0, num(pf.step1Pnl)
        ).run();
      }

      // Restore user settings (object: {key: value})
      const us = (d.user_settings && d.user_settings[acc.id]) || {};
      for (const [key, value] of Object.entries(us)) {
        await env.DB.prepare('INSERT INTO user_settings (account_id, key, value) VALUES (?, ?, ?) ON CONFLICT(account_id, key) DO UPDATE SET value = ?')
          .bind(acc.id, String(key), String(value), String(value)).run();
      }
    }

    return json({ success: true, accounts_restored: accountsRestored, trades_restored: tradesRestored });
  } catch (e) {
    return json({ error: 'Restore failed: ' + e.message }, 500);
  }
}

// =========================================================================
// HELPER
// =========================================================================
function json(data, status = 200, extraHeaders = {}) {
  return new Response(JSON.stringify(data), { status, headers: { 'Content-Type': 'application/json', ...extraHeaders } });
}
